# ================================================================
# PROJETO FERTIRRIGACAO EM CAIXAS - PIVO CENTRAL
# Script Ruby para SketchUp
# ================================================================
#
# COMO USAR:
# 1. Abra o SketchUp (Make ou Pro)
# 2. Va em: Janela > Console Ruby  (Window > Ruby Console)
# 3. No console, digite:
#    load "fertirrigacao_caixas_10mil.rb"
#    (ou o caminho completo do arquivo)
# 4. Pressione Enter
# 5. O modelo sera criado automaticamente
#
# Alternativa: Extensoes > Carregar script
# ================================================================

model = Sketchup.active_model
model.start_operation("Fertirrigacao", true)
ents = model.active_entities

# Materiais
mats = model.materials
m_concrete = mats.add("Concreto")
m_concrete.color = Sketchup::Color.new(166,161,153)
m_tank_white = mats.add("Caixa d'agua")
m_tank_white.color = Sketchup::Color.new(235,230,217)
m_tank_lid = mats.add("Tampa")
m_tank_lid.color = Sketchup::Color.new(204,199,189)
m_pipe_gray = mats.add("Tubo cinza")
m_pipe_gray.color = Sketchup::Color.new(128,128,133)
m_pipe_green = mats.add("Calda/fertilizante")
m_pipe_green.color = Sketchup::Color.new(46,140,56)
m_pipe_blue = mats.add("Agua limpa")
m_pipe_blue.color = Sketchup::Color.new(51,115,199)
m_valve_red = mats.add("Valvula retencao")
